function TitleText({TextOnTitle, MarginOnBot}) {
  return (
    <p style={{display:"flex",
      justifyContent:"center",
      fontFamily:"Arial, sans-serif",
      fontSize:"32px",
      margin:"10px 10px "+{MarginOnBot}+" 10px"}}>
        {TextOnTitle}
    </p>
  );
}

export default TitleText;
